#include <bits/stdc++.h>
#define int long long
using namespace std;
const int mod = 1e9 + 7;
int f[1000005];
int cnt;
int ans;
int exgcd (int a, int b, int &x, int &y) {
	if (b == 0) {
		x = 1;
		y = 0;
		return a;
	}
	int g = exgcd (b, a % b, x, y);
	int t = x;
	x = y;
	y = t - a / b * y;
	return g;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	int k;
	cin >> k;
	f[1] = 1, f[2] = 1, cnt = 2;
	for (int i = 3; f[i - 1] <= k; i++) {
		f[i] = f[i - 1] + f[i - 2];
		cnt++;
	}
	for (int i = 2; i <= cnt; i++) {
		int a = f[i - 1], b = f[i];
		int x, y;
		exgcd (a, b, x, y);
		x *= k;
		y *= k;
		x = (x % b + b) % b;
		if (!x) {
			x = b;
		}
		y = (k - a * x) / b;
		if (y < 0) {
			continue;
		}
		ans = (ans % mod + (y - 1) / a + 1) % mod;
	}
	cout << ans;
	return 0;
}
